          <select
            value={getYear(date)}
            className="year-select"
            onChange={({ target: { value } }) => changeYear(Number(value))}
          >
            {[2017, 2018, 2019].map((year) => (
              <option key={year} value={year}>
                {year}
              </option>
            ))}
          </select>

          <select
            className="month-select"
            value={months[getMonth(date)]}
