            className={clsx(
              "react-datepicker__day-name",
              weekDayClassName,
              disabled ? "react-datepicker__day-name--disabled" : "",
            )}
          >
            {customContent}
          </div>
        );
      }

      // Default render
      return (
        <div
          key={offset}
          role="columnheader"
